package main

import (
	"fmt"
	"html"
	"net/mail"
	"strings"
)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
//
// Security Fixes:
// 1. Header Injection: Sanitizes the subject line by removing CRLF characters to prevent
//    attackers from injecting arbitrary email headers (e.g., Bcc, Cc).
// 2. XSS (Cross-Site Scripting): HTML-escapes user-provided content (username, subject, feedback)
//    before embedding it in the HTML body to prevent malicious script execution in the
//    support staff's email client.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Validate email addresses format using net/mail
	// This helps ensure the addresses are structurally valid.
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	from, err := mail.ParseAddress(fromAddr)
	if err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	to, err := mail.ParseAddress(toAddr)
	if err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Prevent Email Header Injection
	// Remove carriage returns and newlines from the subject to stop attackers from adding new headers.
	safeSubjectHeader := strings.ReplaceAll(strings.ReplaceAll(subject, "\r", ""), "\n", "")

	// Prevent XSS (Cross-Site Scripting)
	// Escape HTML entities in user content to ensure the email client renders text as text, not code.
	safeUserName := html.EscapeString(userName)
	safeSubjectBody := html.EscapeString(subject)
	safeFeedbackContent := html.EscapeString(feedbackContent)

	// Construct email headers
	// Use the String() representation of the parsed addresses to ensure correct formatting.
	emailSubject := fmt.Sprintf("Feedback: %s", safeSubjectHeader)
	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		from.String(),
		to.String(),
		emailSubject,
	)

	// Construct HTML body using sanitized variables
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
</body>
</html>`,
		safeUserName,
		safeSubjectBody,
		safeFeedbackContent,
	)

	// Combine headers and body
	emailMessage := headers + htmlBody

	return emailMessage, nil
}

