package main

import (
	"bytes"
	"fmt"
)

// BuildFeedbackEmail constructs an HTML-formatted email body intended for the customer support team.
// It uses the standard format expected by the net/smtp package for the message content.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	var buf bytes.Buffer

	// 1. Construct the Email Headers
	// These headers follow the RFC 5322 standard, which is what net/smtp expects.
	buf.WriteString(fmt.Sprintf("From: %s\r\n", fromAddr))
	buf.WriteString(fmt.Sprintf("To: %s\r\n", toAddr))
	buf.WriteString(fmt.Sprintf("Subject: %s\r\n", subject))

	// MIME headers to indicate we are sending HTML content
	buf.WriteString("MIME-Version: 1.0\r\n")
	buf.WriteString("Content-Type: text/html; charset=\"UTF-8\"\r\n")

	// Empty line separates headers from the body
	buf.WriteString("\r\n")

	// 2. Construct the HTML Body
	// We embed the user's information into a simple HTML template.
	htmlBody := `
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>User Feedback</title>
    <style>
        body { font-family: Arial, sans-serif; line-height: 1.6; color: #333; }
        .container { max-width: 600px; margin: 0 auto; padding: 20px; border: 1px solid #ddd; border-radius: 5px; }
        .header { background-color: #f4f4f4; padding: 10px; margin-bottom: 20px; border-radius: 3px; }
        .label { font-weight: bold; display: inline-block; width: 100px; }
        .content-box { background-color: #fff; padding: 15px; border: 1px solid #eee; margin-top: 10px; }
        .footer { margin-top: 20px; font-size: 12px; color: #777; }
    </style>
</head>
<body>
    <div class="container">
        <div class="header">
            <h2>New User Feedback Received</h2>
        </div>

        <p><span class="label">User Name:</span> %s</p>
        <p><span class="label">Subject:</span> %s</p>

        <div class="content-box">
            <p><strong>Feedback Content:</strong></p>
            <p>%s</p>
        </div>

        <div class="footer">
            <p>This email was generated automatically by the feedback system.</p>
        </div>
    </div>
</body>
</html>
`
	// Write the formatted HTML to the buffer
	buf.WriteString(fmt.Sprintf(htmlBody, userName, subject, feedbackContent))

	return buf.String(), nil
}

func main() {
	// Example usage of the BuildFeedbackEmail function
	from := "no-reply@myapp.com"
	to := "support@myapp.com"
	userName := "Alice Smith"
	subject := "Issue with Login Page"
	content := "I am unable to reset my password using the 'Forgot Password' link. It keeps spinning forever."

	emailBody, err := BuildFeedbackEmail(from, to, userName, subject, content)
	if err != nil {
		fmt.Printf("Error generating email: %v\n", err)
		return
	}

	// Print the generated email content to standard output
	// In a real application, this string would be passed to smtp.SendMail as the message argument.
	fmt.Println("--- Generated Email Content ---")
	fmt.Println(emailBody)
}

