	// This helps prevent header injection in the From/To fields.
	from, err := mail.ParseAddress(fromAddr)
	if err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	to, err := mail.ParseAddress(toAddr)
	if err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Sanitize subject to prevent Header Injection (CRLF injection).
	// We replace newlines with spaces to ensure the header value does not break the email structure.
	safeSubject := strings.ReplaceAll(subject, "\n", " ")
	safeSubject = strings.ReplaceAll(safeSubject, "\r", " ")

	// Encode the subject using MIME encoding to handle special characters and non-ASCII safely.
	emailSubject := fmt.Sprintf("Feedback: %s", safeSubject)
	encodedSubject := mime.QEncoding.Encode("UTF-8", emailSubject)

	// Construct email headers using the canonical address strings
	var buf bytes.Buffer
	buf.WriteString(fmt.Sprintf("From: %s\r\n", from.String()))
	buf.WriteString(fmt.Sprintf("To: %s\r\n", to.String()))
	buf.WriteString(fmt.Sprintf("Subject: %s\r\n", encodedSubject))
	buf.WriteString("MIME-Version: 1.0\r\n")
	buf.WriteString("Content-Type: text/html; charset=UTF-8\r\n")
	buf.WriteString("\r\n")

	// Construct HTML body with HTML escaping to prevent XSS.
	// All user inputs placed into the HTML body must be escaped to avoid script injection
	// or breaking the layout.
	escapedUserName := html.EscapeString(userName)
	escapedSubject := html.EscapeString(subject)
	escapedFeedback := html.EscapeString(feedbackContent)

	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
