// BuildFeedbackEmail constructs an HTML-formatted email body containing user feedback.
// It returns the raw email content string ready to be sent via net/smtp.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Validate inputs
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("sender and receiver addresses cannot be empty")
	}

	// Use strings.Builder for efficient string concatenation
	var builder strings.Builder

	// --- Email Headers ---
	// Standard SMTP headers
	builder.WriteString(fmt.Sprintf("From: %s\r\n", fromAddr))
	builder.WriteString(fmt.Sprintf("To: %s\r\n", toAddr))
	builder.WriteString(fmt.Sprintf("Subject: %s\r\n", subject))

	// MIME headers to indicate HTML content
	builder.WriteString("MIME-Version: 1.0\r\n")
	builder.WriteString("Content-Type: text/html; charset=UTF-8\r\n")

	// Empty line separates headers from the body
	builder.WriteString("\r\n")

	// --- HTML Body ---
	// Convert newlines in feedback to <br> tags for HTML display
	htmlContent := strings.ReplaceAll(feedbackContent, "\n", "<br>")

	builder.WriteString("<html><body style=\"font-family: Arial, sans-serif; line-height: 1.6;\">")
	builder.WriteString("<div style=\"max-width: 600px; margin: auto; border: 1px solid #eee; padding: 20px;\">")

	builder.WriteString("<h2 style=\"color: #333;\">User Feedback Received</h2>")

	builder.WriteString("<table style=\"width: 100%; border-collapse: collapse; margin-bottom: 20px;\">")
	builder.WriteString(fmt.Sprintf("<tr><td style=\"font-weight: bold; padding: 8px; border-bottom: 1px solid #ddd;\">Username:</td><td style=\"padding: 8px; border-bottom: 1px solid #ddd;\">%s</td></tr>", userName))
	builder.WriteString(fmt.Sprintf("<tr><td style=\"font-weight: bold; padding: 8px; border-bottom: 1px solid #ddd;\">Subject:</td><td style=\"padding: 8px; border-bottom: 1px solid #ddd;\">%s</td></tr>", subject))
	builder.WriteString("</table>")

	builder.WriteString("<div style=\"background-color: #f9f9f9; padding: 15px; border-radius: 5px;\">")
	builder.WriteString("<strong style=\"display: block; margin-bottom: 10px;\">Feedback Content:</strong>")
	builder.WriteString(fmt.Sprintf("<div>%s</div>", htmlContent))
	builder.WriteString("</div>")

	builder.WriteString("</div>")
	builder.WriteString("</body></html>")

	return builder.String(), nil
}

func main() {
	// Example usage of the BuildFeedbackEmail function
	from := "user@example.com"
