import (
	"bytes"
	"fmt"
	"html/template"
	"net/mail"
	"strings"
)

// htmlTemplate defines the structure of the email body.
// Using html/template ensures that special characters in the input
// (userName, subject, feedbackContent) are HTML-escaped, preventing XSS.
const htmlTemplate = `<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> {{.UserName}}</p>
  <p><strong>Subject:</strong> {{.Subject}}</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">{{.FeedbackContent}}</pre>
  </div>
</body>
</html>`

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// 1. Validate Email Addresses
	// We parse the addresses to ensure they are valid RFC 5322 addresses.
	// This also helps in formatting them correctly.
	from, err := mail.ParseAddress(fromAddr)
	if err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	to, err := mail.ParseAddress(toAddr)
	if err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// 2. Sanitize Inputs for Headers (Prevent Header Injection)
	// Header Injection occurs when user input contains CRLF characters (\r\n),
	// allowing an attacker to inject arbitrary headers (e.g., Bcc, Cc).
	// We strip these characters from inputs used in the header section.
	sanitizeHeaderValue := func(s string) string {
		return strings.Map(func(r rune) rune {
			if r == '\r' || r == '\n' {
				return -1
			}
			return r
		}, s)
	}

	safeFrom := sanitizeHeaderValue(from.String())
	safeTo := sanitizeHeaderValue(to.String())
	safeSubject := sanitizeHeaderValue(subject)

	// 3. Construct Headers
	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: Feedback: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		safeFrom,
		safeTo,
		safeSubject,
	)

	// 4. Construct HTML Body (Prevent XSS)
	// We use html/template to safely render the user inputs into the HTML.
	// This automatically escapes HTML special characters (<, >, &, ", ').
	tmpl, err := template.New("feedback").Parse(htmlTemplate)
	if err != nil {
		return "", fmt.Errorf("failed to parse template: %w", err)
	}

	var bodyBuf bytes.Buffer
	data := struct {
		UserName        string
		Subject         string
		FeedbackContent string
	}{
		UserName:        userName,
		Subject:         subject,
		FeedbackContent: feedbackContent,
	}

	if err := tmpl.Execute(&bodyBuf, data); err != nil {
		return "", fmt.Errorf("failed to execute template: %w", err)
	}

	// 5. Combine Headers and Body
	return headers + bodyBuf.String(), nil
}

