package main

import (
	"fmt"
	"html"
	"mime"
	"net/mail"
	"strings"
)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// 1. Validate and Parse Email Addresses
	// This ensures the addresses are RFC 5322 compliant and helps prevent header injection
	// by using the library's String() method for formatting.
	from, err := mail.ParseAddress(fromAddr)
	if err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	to, err := mail.ParseAddress(toAddr)
	if err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// 2. Sanitize Header Fields to prevent Header Injection (SMTP Injection)
	// Remove carriage returns and newlines from any string used in headers.
	sanitizeHeaderValue := func(s string) string {
		return strings.Map(func(r rune) rune {
			if r == '\r' || r == '\n' {
				return -1
			}
			return r
		}, s)
	}

	// Prepare subject for the header
	// We sanitize it first to remove CRLF, then MIME encode it to handle special characters safely.
	cleanSubject := sanitizeHeaderValue(subject)
	emailSubject := fmt.Sprintf("Feedback: %s", cleanSubject)
	encodedSubject := mime.BEncoding.Encode("UTF-8", emailSubject)

	// 3. Construct Email Headers
	// Using the String() method of mail.Address ensures proper formatting.
	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		from.String(),
		to.String(),
		encodedSubject,
	)

	// 4. Construct HTML Body
	// Escape HTML entities in all user inputs to prevent Cross-Site Scripting (XSS).
	escapedUserName := html.EscapeString(userName)
	escapedSubject := html.EscapeString(subject)
	escapedFeedbackContent := html.EscapeString(feedbackContent)

	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
</body>
</html>`,
		escapedUserName,
		escapedSubject,
		escapedFeedbackContent,
	)

	// 5. Combine headers and body
	emailMessage := headers + htmlBody

	return emailMessage, nil
}

