package main

import (
	"fmt"
	"mime"
	"net/mail"
	"strings"
)

// BuildFeedbackEmail constructs an RFC 5322 formatted email message with HTML content.
// It is designed to be used with the net/smtp.SendMail function.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Validate and format the From address
	from, err := mail.ParseAddress(fromAddr)
	if err != nil {
		return "", fmt.Errorf("invalid from address: %w", err)
	}

	// Validate and format the To address
	to, err := mail.ParseAddress(toAddr)
	if err != nil {
		return "", fmt.Errorf("invalid to address: %w", err)
	}

	// Encode the subject header to handle non-ASCII characters properly (RFC 2047)
	encodedSubject := mime.QEncoding.Encode("UTF-8", subject)

	// Build the HTML Body
	// We use a helper function to escape HTML entities to prevent injection and ensure valid rendering.
	htmlBody := buildHTMLBody(userName, subject, feedbackContent)

	// Construct the full email message
	var builder strings.Builder

	// 1. Headers
	builder.WriteString(fmt.Sprintf("From: %s\r\n", from.String()))
	builder.WriteString(fmt.Sprintf("To: %s\r\n", to.String()))
	builder.WriteString(fmt.Sprintf("Subject: %s\r\n", encodedSubject))
	builder.WriteString("MIME-Version: 1.0\r\n")
	builder.WriteString("Content-Type: text/html; charset=UTF-8\r\n")
	builder.WriteString("Content-Transfer-Encoding: quoted-printable\r\n")

	// 2. Empty line separating headers from body
	builder.WriteString("\r\n")

	// 3. Body
	builder.WriteString(htmlBody)

	return builder.String(), nil
}

// buildHTMLBody creates the HTML content for the email.
func buildHTMLBody(userName, subject, content string) string {
	// Basic HTML structure with inline CSS for better readability
	const htmlTemplate = `
<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <title>User Feedback</title>
</head>
<body style="font-family: Arial, sans-serif; line-height: 1.6; color: #333;">
    <div style="max-width: 600px; margin: 0 auto; padding: 20px; border: 1px solid #ddd; border-radius: 5px;">
        <h2 style="color: #2c3e50;">New User Feedback Received</h2>

        <div style="background-color: #f9f9f9; padding: 15px; border-radius: 4px; margin-bottom: 20px;">
            <p><strong>Username:</strong> %s</p>
            <p><strong>Subject:</strong> %s</p>
        </div>

        <h3 style="color: #2c3e50; border-bottom: 1px solid #eee; padding-bottom: 10px;">Feedback Content:</h3>

        <div style="white-space: pre-wrap; background-color: #fff; padding: 10px; border-left: 3px solid #3498db;">
            %s
        </div>

        <hr style="border: 0; border-top: 1px solid #eee; margin: 30px 0;">
        <p style="font-size: 12px; color: #999;">This email was generated automatically by the feedback system.</p>
    </div>
</body>
</html>
`
	// Escape user input to prevent HTML injection
	return fmt.Sprintf(htmlTemplate,
		escapeHTML(userName),
		escapeHTML(subject),
		escapeHTML(content),
	)
}

// escapeHTML replaces special characters to prevent HTML injection.
func escapeHTML(s string) string {
	s = strings.ReplaceAll(s, "&", "&amp;")
	s = strings.ReplaceAll(s, "<", "&lt;")
	s = strings.ReplaceAll(s, ">", "&gt;")
	s = strings.ReplaceAll(s, "\"", "&quot;")
	s = strings.ReplaceAll(s, "'", "&#39;")
	return s
}

func main() {
	// Example usage
	from := "noreply@example.com"
	to := "support@example.com"
	userName := "John Doe"
	subject := "Issue with Login Page"
	feedback := "I am unable to log in using my Google account. The button just spins forever."

	emailContent, err := BuildFeedbackEmail(from, to, userName, subject, feedback)
	if err != nil {
		fmt.Printf("Error building email: %v\n", err)
		return
	}

	// Print the generated email content to console
	// In a real application, this would be passed to smtp.SendMail
	fmt.Println("--- Generated Email Content ---")
	fmt.Println(emailContent)
	fmt.Println("------------------------------")
}

