// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// 1. Validate and parse email addresses to prevent header injection via address fields.
	// Using mail.ParseAddress ensures the address format is valid and strips potentially
	// malicious characters often used in SMTP injection.
	from, err := mail.ParseAddress(fromAddr)
	if err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	to, err := mail.ParseAddress(toAddr)
	if err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// 2. Sanitize inputs for headers to prevent Header Injection (CRLF attacks).
	// We define a helper to remove carriage returns and line feeds.
	sanitizeHeader := func(s string) string {
		return strings.NewReplacer("\r", " ", "\n", " ").Replace(s)
	}

	// 3. Construct Headers
	var buf bytes.Buffer

	// Use the parsed address strings (.String()) to ensure valid format in headers.
	buf.WriteString(fmt.Sprintf("From: %s\r\n", from.String()))
	buf.WriteString(fmt.Sprintf("To: %s\r\n", to.String()))

	// Sanitize the subject to remove newlines before encoding.
	cleanSubject := sanitizeHeader(subject)

	// Use MIME encoding for the subject. This handles non-ASCII characters correctly
	// and ensures the header value is safely encoded, preventing injection.
	encodedSubject := mime.BEncoding.Encode("UTF-8", cleanSubject)
	buf.WriteString(fmt.Sprintf("Subject: Feedback: %s\r\n", encodedSubject))

	buf.WriteString("MIME-Version: 1.0\r\n")
	buf.WriteString("Content-Type: text/html; charset=UTF-8\r\n")
	buf.WriteString("\r\n")

	// 4. Construct HTML Body
	// Escape HTML entities in all user inputs to prevent Cross-Site Scripting (XSS).
	// This protects the support staff viewing the email in a browser-based client.
	escapedUserName := html.EscapeString(userName)
	escapedSubject := html.EscapeString(subject)
	escapedFeedback := html.EscapeString(feedbackContent)

	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
</body>
</html>`,
		escapedUserName,
		escapedSubject,
		escapedFeedback,
	)

	buf.WriteString(htmlBody)

	return buf.String(), nil
}

