	safeTo := sanitizeHeaderValue(toAddr)
	safeSubject := sanitizeHeaderValue(subject)

	// Security Fix 2: Prevent Cross-Site Scripting (XSS)
	// Escape HTML entities in user-generated content before embedding in the HTML body.
	// This prevents malicious scripts from executing when support staff view the email.
	escapedUserName := html.EscapeString(userName)
	escapedSubject := html.EscapeString(subject)
	escapedContent := html.EscapeString(feedbackContent)

	// Construct email headers
	emailSubject := fmt.Sprintf("Feedback: %s", safeSubject)

	// Use quoted-printable or base64 if subject has non-ASCII, but assume ASCII for simplicity
	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		safeFrom,
