package main

import (
	"bytes"
	"fmt"
)

// BuildFeedbackEmail constructs an HTML email body containing user feedback.
// It returns the formatted email content as a string ready to be sent via net/smtp.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	var buf bytes.Buffer

	// 1. Write Email Headers
	// These headers are required by the net/smtp package when sending the message
	buf.WriteString(fmt.Sprintf("From: %s\r\n", fromAddr))
	buf.WriteString(fmt.Sprintf("To: %s\r\n", toAddr))
	buf.WriteString(fmt.Sprintf("Subject: %s\r\n", subject))

	// MIME headers to indicate this is an HTML email
	buf.WriteString("MIME-Version: 1.0\r\n")
	buf.WriteString("Content-Type: text/html; charset=UTF-8\r\n")

	// Empty line separates headers from the body
	buf.WriteString("\r\n")

	// 2. Write HTML Body
	// We use a simple HTML template to format the feedback information clearly
	htmlTemplate := `
<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <title>User Feedback</title>
    <style>
        body { font-family: 'Helvetica Neue', Helvetica, Arial, sans-serif; line-height: 1.6; color: #333; }
        .container { max-width: 600px; margin: 0 auto; padding: 20px; border: 1px solid #e0e0e0; border-radius: 8px; background-color: #f9f9f9; }
        .header { background-color: #007bff; color: #ffffff; padding: 15px; border-radius: 8px 8px 0 0; margin: -20px -20px 20px -20px; }
        .header h2 { margin: 0; font-size: 20px; }
        .label { font-weight: bold; color: #555; display: inline-block; width: 100px; }
        .value { color: #000; }
        .feedback-box { background-color: #ffffff; border: 1px solid #ddd; padding: 15px; border-radius: 5px; margin-top: 10px; }
        .feedback-content { white-space: pre-wrap; }
    </style>
</head>
<body>
    <div class="container">
        <div class="header">
            <h2>New User Feedback Received</h2>
        </div>

        <p><span class="label">From:</span> <span class="value">%s</span></p>
        <p><span class="label">Username:</span> <span class="value">%s</span></p>
        <p><span class="label">Subject:</span> <span class="value">%s</span></p>

        <div class="feedback-box">
            <p><strong>Feedback Content:</strong></p>
            <div class="feedback-content">%s</div>
        </div>

        <br>
        <p style="font-size: 12px; color: #888;">This email was generated automatically by the feedback system.</p>
    </div>
</body>
</html>
`

	// Format the HTML with the provided data
	buf.WriteString(fmt.Sprintf(htmlTemplate, fromAddr, userName, subject, feedbackContent))

	return buf.String(), nil
}

func main() {
	// Example usage of the BuildFeedbackEmail function
