package main

import (
	"bytes"
	"fmt"
	"html/template"
	"net/mail"
	"strings"
)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// It addresses security vulnerabilities including Header Injection and XSS.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate email addresses format
	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Security Fix 1: Prevent Header Injection (SMTP Injection)
	// Sanitize inputs used in headers by removing carriage returns and newlines.
	// This prevents attackers from injecting arbitrary headers (e.g., Bcc, Cc).
	sanitizeHeader := func(s string) string {
		return strings.Map(func(r rune) rune {
			if r == '\r' || r == '\n' {
				return -1
			}
			return r
		}, s)
	}

	safeFrom := sanitizeHeader(fromAddr)
	safeTo := sanitizeHeader(toAddr)
	safeSubject := sanitizeHeader(subject)

	// Construct email headers
	emailSubject := fmt.Sprintf("Feedback: %s", safeSubject)

	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		safeFrom,
		safeTo,
		emailSubject,
	)

	// Security Fix 2: Prevent Cross-Site Scripting (XSS)
	// Use html/template to automatically escape HTML entities in user inputs.
	// This ensures that any malicious scripts or tags in the feedback content
	// are displayed as text rather than executed by the email client.
	const htmlTemplate = `<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> {{.UserName}}</p>
  <p><strong>Subject:</strong> {{.Subject}}</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">{{.FeedbackContent}}</pre>
  </div>
</body>
</html>`

	tmpl, err := template.New("feedback").Parse(htmlTemplate)
	if err != nil {
		return "", fmt.Errorf("failed to parse html template: %w", err)
	}

	var bodyBuffer bytes.Buffer
	data := struct {
		UserName        string
		Subject         string
		FeedbackContent string
	}{
		UserName:        userName,
		Subject:         subject,
		FeedbackContent: feedbackContent,
	}

	if err := tmpl.Execute(&bodyBuffer, data); err != nil {
		return "", fmt.Errorf("failed to execute html template: %w", err)
	}

	// Combine headers and body
	emailMessage := headers + bodyBuffer.String()

	return emailMessage, nil
}

