// BuildFeedbackEmail constructs an HTML-formatted email body based on user feedback.
// It returns the raw email content including headers, ready to be sent via net/smtp.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	var buf bytes.Buffer

	// 1. Construct Email Headers
	// These headers are standard for SMTP transmission
	buf.WriteString(fmt.Sprintf("From: %s\r\n", fromAddr))
	buf.WriteString(fmt.Sprintf("To: %s\r\n", toAddr))
	buf.WriteString(fmt.Sprintf("Subject: %s\r\n", subject))
	buf.WriteString("MIME-Version: 1.0\r\n")
	// Specify content type as HTML and charset as UTF-8 for proper rendering
	buf.WriteString("Content-Type: text/html; charset=UTF-8\r\n")

	// 2. Header-Body Separator
	// An empty line separates the headers from the email body
	buf.WriteString("\r\n")

	// 3. Construct HTML Body
	// We use a simple HTML template to format the feedback nicely
	htmlTemplate := `
<html>
<head>
    <style>
        body { font-family: Arial, sans-serif; line-height: 1.6; color: #333; }
        .container { max-width: 600px; margin: 0 auto; padding: 20px; border: 1px solid #ddd; border-radius: 5px; background-color: #f9f9f9; }
        .header { background-color: #007bff; color: white; padding: 10px 20px; border-radius: 5px 5px 0 0; margin: -20px -20px 20px -20px; }
        .label { font-weight: bold; color: #555; }
        .content-box { background-color: #fff; padding: 15px; border: 1px solid #eee; border-radius: 4px; }
    </style>
</head>
<body>
    <div class="container">
        <div class="header">
            <h2>New User Feedback</h2>
        </div>
        <p><span class="label">Username:</span> %s</p>
        <p><span class="label">Subject:</span> %s</p>

        <p><span class="label">Feedback Content:</span></p>
        <div class="content-box">
            %s
        </div>

        <br>
        <p style="font-size: 0.9em; color: #777;">This email was generated automatically by the feedback system.</p>
    </div>
</body>
</html>
`

	// Replace newlines in feedback content with <br> tags for HTML display
	safeContent := strings.ReplaceAll(feedbackContent, "\n", "<br>")

	// Write the formatted HTML to the buffer
	buf.WriteString(fmt.Sprintf(htmlTemplate, userName, subject, safeContent))

	return buf.String(), nil
}

func main() {
	// Example usage of the BuildFeedbackEmail function
	from := "no-reply@myapp.com"
	to := "support-team@myapp.com"
	userName := "jdoe_123"
